  static String translate(String locale, String key) {
    final lang = supportedLocales.contains(locale) ? locale : 'en';
    final map = _byLocale[lang];
    if (map != null) {
      final v = map[key];
      if (v != null) return v;
    }
    final en = _byLocale['en']![key];
    if (en != null) return en;
    return _humanize(key);
  }

  static String _humanize(String key) {
    final base = key
        .replaceFirst('wheel_note_', '')
        .replaceFirst('wheel_sub_', '')
        .replaceFirst('wheel_cat_', '')
        .replaceAll('_', ' ');
    if (base.isEmpty) return key;
    return base
        .split(' ')
        .map((s) {
          if (s.isEmpty) return s;
          return s[0].toUpperCase() + s.substring(1);
        })
        .join(' ');
  }
